/**
 * Event Explorer Plugin
 * -----------------------
 * Plugin ini mendemonstrasikan bagaimana opencode events bekerja.
 * Setiap hook akan menampilkan log ke console sehingga Anda bisa
 * melihat urutan dan data yang mengalir di setiap event.
 *
 * рҹ”Қ Model Tracker: menyimpan model apa yang dipakai setiap kali
 * prompt dikirim, termasuk provider-nya.
 */
export default (async () => {
  // --- State untuk custom tool events_status ---
  const eventCounts: Record<string, number> = {};
  const eventLog: Array<{ event: string; time: string; data?: unknown }> = [];

  // --- Model tracking ---
  let configuredModel: string | null = null;
  let lastUsedModel: string | null = null;
  let modelHistory: Array<{
    model: string;
    timestamp: string;
    temperature?: number;
    maxTokens?: number;
  }> = [];

  function track(eventName: string, data?: unknown) {
    eventCounts[eventName] = (eventCounts[eventName] || 0) + 1;
    eventLog.push({ event: eventName, time: new Date().toISOString(), data });
  }

  function log(emoji: string, msg: string, data?: unknown) {
    const prefix = "[EVENT EXPLORER]";
    if (data) {
      console.log(`${prefix} ${emoji} ${msg}`, JSON.stringify(data, null, 2));
    } else {
      console.log(`${prefix} ${emoji} ${msg}`);
    }
  }

  /**
   * Tampilkan banner model dengan border biar keliatan mencolok.
   */
  function printModelBanner(label: string, model: string, extra?: string) {
    const border = "в•җ".repeat(60);
    console.log("");
    console.log(`  в•”${border}в•—`);
    console.log(`  в•‘  рҹҺҜ ${label.padEnd(53)}в•‘`);
    console.log(`  в•‘  ${`Model: ${model}`.padEnd(56)}в•‘`);
    if (extra) {
      console.log(`  в•‘  ${extra.padEnd(56)}в•‘`);
    }
    console.log(`  в•ҡ${border}в•қ`);
    console.log("");
  }

  return {
    // ==========================================
    // 1. CONFIG вҖ” dipanggil sekali saat init
    // ==========================================
    config: (cfg) => {
      configuredModel = cfg.model ?? null;
      track("config");

      // Banner besar untuk configured model
      const text = configuredModel
        ? `рҹҺҜ  Configured Model: ${configuredModel}`
        : "вҡ пёҸ  No model configured in opencode.json";

      const border = "в–Ҳ".repeat(54);
      console.log("");
      console.log(`  в–Ҳ${border}в–Ҳ`);
      console.log(`  в–Ҳ  ${"рҹ”§ EVENT EXPLORER вҖ” ACTIVE".padEnd(50)}в–Ҳ`);
      console.log(`  в–Ҳ  ${text.padEnd(50)}в–Ҳ`);
      if (cfg.small_model) {
        console.log(`  в–Ҳ  ${`Small model: ${cfg.small_model}`.padEnd(50)}в–Ҳ`);
      }
      console.log(`  в–Ҳ${border}в–Ҳ`);
      console.log("");

      log("рҹ“Ӣ", `Username: ${cfg.username ?? "(not set)"}`);
      log("рҹ“Ұ", `Plugins terdaftar: ${(cfg.plugin ?? []).length} entries`);
    },

    // ==========================================
    // 2. TOOL EXECUTION вҖ” sebelum & sesudah
    // ==========================================
    "tool.execute.before": async (input, output) => {
      track("tool.execute.before", { name: input.name });
      log("вҡЎ", `BEFORE: "${input.name}"`, {
        args: output.args,
        toolCallId: input.toolCallId,
      });
    },

    "tool.execute.after": async (input, output) => {
      const status = output.error ? "вқҢ ERROR" : "вң… SUCCESS";
      track("tool.execute.after", {
        name: input.name,
        status: output.error ? "error" : "success",
      });
      log(status, `AFTER: "${input.name}"`, {
        duration: output.durationMs ? `${output.durationMs}ms` : "unknown",
        resultTruncated: output.result
          ? output.result.toString().substring(0, 200)
          : "(no result)",
        error: output.error ?? undefined,
      });
    },

    // ==========================================
    // 3. TOOL DEFINITION вҖ” saat tool didaftarkan
    // ==========================================
    "tool.definition": async (input, output) => {
      track("tool.definition", { name: input.name });
      log("рҹӣ пёҸ", `Tool definition registered: "${input.name}"`);
    },

    // ==========================================
    // 4. CHAT вҖ” message & params ke LLM
    // ==========================================
    "chat.message": async (input, output) => {
      track("chat.message");
      const role = output?.role ?? "unknown";
      const contentPreview = output?.content
        ? output.content.toString().substring(0, 100)
        : "(empty)";
      log("рҹ’¬", `Chat message [${role}]: "${contentPreview}..."`);
    },

    "chat.params": async (input, output) => {
      track("chat.params");

      // Ambil model dari params
      const model = output?.model as string | undefined;
      if (model) {
        lastUsedModel = model;
        const timestamp = new Date().toISOString();
        modelHistory.push({
          model,
          timestamp,
          temperature: output?.temperature as number | undefined,
          maxTokens: output?.max_tokens as number | undefined,
        });

        // Tampilkan banner mencolok setiap prompt dikirim
        const provider = model.includes("/") ? model.split("/")[0] : "unknown";
        const modelName = model.includes("/") ? model.split("/").slice(1).join("/") : model;
        printModelBanner(
          `рҹҡҖ PROMPT SENT вҖ” ${timestamp}`,
          model,
          `Provider: ${provider}  |  Model: ${modelName}  |  Temp: ${output?.temperature ?? "default"}`
        );
      } else {
        log("рҹ§ ", "LLM Params disusun (model tidak terdeteksi di params)", {
          semuaKeys: output ? Object.keys(output as object) : "(empty)",
        });
      }

      log("рҹ§ ", "LLM Params detail", {
        model: output?.model ?? "вҡ пёҸ TIDAK TERDETEKSI",
        maxTokens: output?.max_tokens,
        temperature: output?.temperature,
        stream: output?.stream,
        presencePenalty: output?.presence_penalty,
        frequencyPenalty: output?.frequency_penalty,
        topP: output?.top_p,
        stop: output?.stop,
      });
    },

    "chat.headers": async (input, output) => {
      track("chat.headers");
      // Header HTTP request ke provider вҖ” mungkin ada model info juga
      const headers = output as Record<string, string> | undefined;
      if (headers) {
        const relevantHeaders = ["x-model", "x-request-id", "content-type", "authorization"];
        const found: Record<string, string> = {};
        for (const h of relevantHeaders) {
          const val = headers[h] ?? headers[h.toLowerCase()];
          if (val) {
            // Jangan tampilkan full token/api key
            found[h] = h === "authorization" ? `${val.substring(0, 15)}...` : val;
          }
        }
        if (Object.keys(found).length > 0) {
          log("рҹ“Ё", "Chat request headers", found);
        } else {
          log("рҹ“Ё", "Chat request dikirim (headers tidak mengandung model info)");
        }
      }
    },

    // ==========================================
    // 5. PERMISSION вҖ” saat user dimintai izin
    // ==========================================
    "permission.ask": async (input, output) => {
      track("permission.ask");
      log("рҹ”җ", `Permission asked: "${input?.action ?? "unknown action"}"`, {
        tool: input?.tool,
        args: input?.args,
      });
    },

    // ==========================================
    // 6. SHELL ENV вҖ” environment variables
    // ==========================================
    "shell.env": async (input, output) => {
      track("shell.env");
      const envKeys = Object.keys(output ?? {}).slice(0, 10);
      log(
        "рҹҢҗ",
        `Shell env dimuat (${Object.keys(output ?? {}).length} vars)`,
        { sample: envKeys }
      );
    },

    // ==========================================
    // 7. COMMAND EXECUTION
    // ==========================================
    "command.execute.before": async (input, output) => {
      track("command.execute.before");
      log("рҹ“ҹ", `Custom command dijalankan: "${input?.name ?? "unknown"}"`);
    },

    // ==========================================
    // 8. CUSTOM TOOLS
    // ==========================================
    tool: {
      // -------------------------------------------
      // Tool #1: Lihat model yang sedang aktif
      // -------------------------------------------
      current_model: {
        description:
          "Menampilkan model LLM yang sedang digunakan oleh opencode saat ini. Meliputi model dari config, model terakhir yang dipakai, dan riwayat model.",
        parameters: {
          history: {
            type: "string",
            enum: ["yes", "no"],
            description:
              '"yes" = tampilkan riwayat model (default), "no" = hanya model aktif sekarang',
          },
        },
        execute: async ({ history }: { history?: string }) => {
          let output = "";

          const border = "в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ";
          output += `в•”${border}в•—\n`;
          output += `в•‘  рҹҺҜ  MODEL LLM YANG SEDANG AKTIF              в•‘\n`;
          output += `в•ҡ${border}в•қ\n\n`;

          output += `рҹ“Ӣ Model dari config opencode.json:\n`;
          output += `   ${configuredModel ?? "вҡ пёҸ  Tidak ada (default provider akan dipakai)"}\n\n`;

          output += `рҹ”„ Model terakhir dipakai:\n`;
          output += `   ${lastUsedModel ?? "вҸі Belum ada prompt yang dikirim"}\n\n`;

          if (lastUsedModel && lastUsedModel.includes("/")) {
            const [provider, ...rest] = lastUsedModel.split("/");
            output += `рҹ“Ҡ Informasi provider:\n`;
            output += `   Provider : ${provider}\n`;
            output += `   Model    : ${rest.join("/")}\n`;
            output += `   Format   : provider/model-id\n\n`;
          }

          if (history !== "no" && modelHistory.length > 0) {
            output += `рҹ“ң Riwayat model (${modelHistory.length} prompt):\n`;
            output += `   ${"#".padEnd(3)} ${"Waktu".padEnd(24)} ${"Model".padEnd(30)} ${"Temp".padEnd(6)}\n`;
            output += `   ${"-".repeat(3)} ${"-".repeat(24)} ${"-".repeat(30)} ${"-".repeat(6)}\n`;
            modelHistory.forEach((entry, i) => {
              output += `   ${(i + 1).toString().padEnd(3)} ${entry.timestamp.padEnd(24)} ${entry.model.padEnd(30)} ${(entry.temperature?.toString() ?? "-").padEnd(6)}\n`;
            });
          } else if (modelHistory.length === 0) {
            output += `рҹ“ң Riwayat model: (kosong вҖ” belum ada prompt)\n`;
          }

          output += `\nрҹ’Ў Tips:\n`;
          output += `   вҖў Model di-set di opencode.json вҶ’ field "model"\n`;
          output += `   вҖў Bisa juga di-set per-agent вҶ’ "agent.{name}.model"\n`;
          output += `   вҖў Format: "provider/model-id" (contoh: "anthropic/claude-sonnet-4-6")\n`;
          output += `   вҖў "small_model" dipakai untuk task ringan\n`;

          return output;
        },
      },

