{"filePath":"/home/runner/plugin_coba/.opencode/plugins/messaging.ts","content":"import type { Plugin } from "@opencode-ai/plugin";
import * as fs from "fs";
import * as path from "path";

const DIR = path.join(process.cwd() || ".", ".opencode");
const LOG = path.join(DIR, "messaging.log");
const INBOX = path.join(DIR, "messaging-inbox.json");

if (!fs.existsSync(DIR)) fs.mkdirSync(DIR, { recursive: true });

function log(text: string) {
  try { fs.appendFileSync(LOG, text, "utf-8"); } catch { /* silent */ }
}

function readInbox(): Array<Record<string, unknown>> {
  try {
    if (fs.existsSync(INBOX))
      return JSON.parse(fs.readFileSync(INBOX, "utf-8"));
  } catch { /* ignore */ }
  return [];
}

function saveInbox(m: unknown[]) {
  fs.writeFileSync(INBOX, JSON.stringify(m, null, 2), "utf-8");
}

const AGENTS = [
  { id: "pm", name: "Project Manager", emoji: "рҹ‘”" },
  { id: "architect", name: "Architect", emoji: "рҹҸ—пёҸ" },
  { id: "developer", name: "Developer", emoji: "рҹ‘ЁвҖҚрҹ’»" },
  { id: "qa", name: "QA Engineer", emoji: "рҹ§Ә" },
  { id: "devops", name: "DevOps", emoji: "вҡҷпёҸ" },
];

export default (() => {
  log("рҹҡҖ MESSAGING PLUGIN STARTED\n");

  return {
    tool: {
      inter_agent_demo_help: {
        description: "Menampilkan bantuan semua tool inter-agent messaging.",
        parameters: {},
        execute: async () => {
          let out = `в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n`;
          out += `в•‘  рҹӨ–  INTER-AGENT MESSAGING                   в•‘\n`;
          out += `в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n`;
          out += `рҹ“Ӣ Tools:\n`;
          out += `  inter_agent_send         рҹ“Ө Kirim pesan antar agent\n`;
          out += `  inter_agent_inbox        рҹ“Ё Lihat pesan masuk\n`;
          out += `  inter_agent_conversation рҹ’¬ Lihat thread percakapan\n\n`;
          out += `Agent: pm, architect, developer, qa, devops\n`;
          out += `Types: result, review_request, review_response, clarification, approval, revision\n\n`;
          out += `рҹ“Ғ ${LOG}\nрҹ“Ғ ${INBOX}\n`;
          return out;
        },
      },

      inter_agent_send: {
        description: "рҹ“Ө Kirim pesan antar agent.",
        parameters: {
          from: { type: "string", enum: ["pm", "architect", "developer", "qa", "devops"], description: "Pengirim" },
          to: { type: "string", enum: ["pm", "architect", "developer", "qa", "devops"], description: "Penerima" },
          type: { type: "string", enum: ["result", "review_request", "review_response", "clarification", "approval", "revision"], description: "Tipe" },
          message: { type: "string", description: "Isi pesan" },
          taskId: { type: "string", description: "Task ID" },
        },
        execute: async ({ from, to, type, message, taskId }: Record<string, string>) => {
          const s = AGENTS.find((a) => a.id === from);
          const r = AGENTS.find((a) => a.id === to);
          if (!s || !r) return "вқҢ Role tidak valid.";
          const tid = taskId || `msg-${Date.now()}`;
          const emoji: Record<string, string> = { result: "вң…", review_request: "рҹ”Қ", review_response: "рҹ“қ", clarification: "вқ“", approval: "рҹ‘Қ", revision: "рҹ”„" };
          const inbox = readInbox();
          inbox.push({ from, to, type, message, time: new Date().toISOString(), taskId: tid, read: false });
          saveInbox(inbox);
          log(`рҹ“Ё ${from}вҶ’${to} [${type}] ${message}\n`);
          return `в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\nв•‘  рҹ“Ё  PESAN TERKIRIM                  в•‘\nв•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n${s.emoji} ${s.name} вҶ’ ${r.emoji} ${r.name}\n${emoji[type] || "рҹ“Ё"} ${type}\nрҹҶ” ${tid}\nрҹ’¬ "${message}"\n\nрҹ“Ғ ${LOG}\n`;
        },
      },

      inter_agent_inbox: {
        description: "рҹ“Ё Lihat pesan masuk.",
        parameters: {
          role: { type: "string", enum: ["pm", "architect", "developer", "qa", "devops", "all"], description: "Filter role" },
          status: { type: "string", enum: ["all", "unread"], description: "Filter status" },
        },
        execute: async ({ role, status }: { role?: string; status?: string }) => {
          let msgs = readInbox();
          const r = role || "all";
          if (r !== "all") msgs = msgs.filter((m) => m.from === r || m.to === r);
          if (status === "unread") msgs = msgs.filter((m) => !m.read);
          if (msgs.length === 0) return "рҹ“ӯ Inbox kosong.";
          const emoji: Record<string, string> = { result: "вң…", review_request: "рҹ”Қ", review_response: "рҹ“қ", clarification: "вқ“", approval: "рҹ‘Қ", revision: "рҹ”„" };
          let out = `в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\nв•‘  рҹ“Ё  INBOX${r === "all" ? " ALL" : " " + r.toUpperCase()}${status === "unread" ? " (UNREAD)" : ""}${" ".repeat(20)}\nв•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n`;
          const grouped: Record<string, typeof msgs> = {};
          for (const m of msgs) {
            const k = (m.taskId as string) || "?";
            if (!grouped[k]) grouped[k] = [];
            grouped[k].push(m);
          }
          for (const [tid, group] of Object.entries(grouped)) {
            out += `  рҹҶ” ${tid}\n`;
            for (const m of group) {
              const a = AGENTS.find((x) => x.id === m.from);
              const te = emoji[m.type as string] || "рҹ“Ё";
              const unreadTag = m.read ? "" : " рҹҶ•";
              out += `    ${a?.emoji || "рҹӨ–"} ${m.from} ${te} [${m.type}]${unreadTag}\n      "${(m.message as string).substring(0, 80)}"\n`;
            }
          }
          out += `\nрҹ“Ғ ${INBOX}\n`;
          return out;
        },
      },

      inter_agent_conversation: {
        description: "рҹ’¬ Lihat thread percakapan.",
        parameters: {
          taskId: { type: "string", description: "Task ID" },
        },
        execute: async ({ taskId }: { taskId: string }) => {
          if (!taskId) return "вқҢ Parameter taskId wajib.";
          const all = readInbox();
          const thread = all.filter((m) => m.taskId === taskId);
          if (thread.length === 0) return `рҹ“ӯ Tidak ada percakapan untuk "${taskId}".`;
          const emoji: Record<string, string> = { result: "вң…", review_request: "рҹ”Қ", review_response: "рҹ“қ", clarification: "вқ“", approval: "рҹ‘Қ", revision: "рҹ”„" };
          let out = `в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\nв•‘  рҹ’¬  ${taskId.substring(0, 28).padEnd(28)}в•‘\nв•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n`;
          for (let i = 0; i < thread.length; i++) {
            const m = thread[i];
            const s = AGENTS.find((a) => a.id === m.from);
            const r = AGENTS.find((a) => a.id === m.to);
            out += `  [${i + 1}] ${s?.emoji || "рҹӨ–"} ${s?.name || m.from} вҶ’ ${r?.emoji || "рҹӨ–"} ${r?.name || m.to}\n  ${emoji[m.type as string] || "рҹ“Ё"} ${(m.type as string).toUpperCase()}\n  рҹ’¬ "${(m.message as string).substring(0, 80)}"\n  вҸұ ${m.time}\n\n`;
          }
          out += `рҹ“Ғ ${LOG}\n`;
          return out;
        },
      },
    },
  };
}) satisfies Plugin;
"}

{"filePath":"/home/runner/plugin_coba/.opencode/plugins/pipeline.ts","content":"import type { Plugin } from "@opencode-ai/plugin";
import * as fs from "fs";
import * as path from "path";

const DIR = path.join(process.cwd() || ".", ".opencode");
const LOG = path.join(DIR, "pipeline.log");
const DATA = path.join(DIR, "pipeline-data.json");

if (!fs.existsSync(DIR)) fs.mkdirSync(DIR, { recursive: true });

function log(text: string) {
  try { fs.appendFileSync(LOG, text, "utf-8"); } catch { /* silent */ }
}
function readData(): Record<string, unknown>[] {
  try { return JSON.parse(fs.readFileSync(DATA, "utf-8")); } catch { return []; }
}
function saveData(d: unknown[]) {
  fs.writeFileSync(DATA, JSON.stringify(d, null, 2), "utf-8");
}

const LABELS: Record<string, string> = {
  pm: "рҹ‘” PM", architect: "рҹҸ—пёҸ Architect", developer: "рҹ‘ЁвҖҚрҹ’» Developer", qa: "рҹ§Ә QA", devops: "вҡҷпёҸ DevOps",
};

export default (() => {
  log("рҹҸ—пёҸ PIPELINE PLUGIN STARTED\n");

  return {
    tool: {
      inter_agent_pipeline: {
        description: "рҹҸ—пёҸ Pipeline multi-agent: PMвҶ’ArchitectвҶ’DeveloperвҶ’QA.",
        parameters: {
          template: { type: "string", enum: ["feature", "bugfix", "review"], description: "Template" },
          featureName: { type: "string", description: "Nama fitur/bug" },
        },
        execute: async ({ template, featureName }: { template?: string; featureName?: string }) => {
          const tpl = template || "feature";
          const name = featureName || "fitur-demo";
          const taskId = `pipe-${tpl}-${Date.now()}`;

          const stages: Record<string, { from: string; to: string; type: string; message: string }[]> = {
            feature: [
              { from: "pm", to: "architect", type: "result", message: `Desain arsitektur untuk: "${name}"` },
              { from: "architect", to: "developer", type: "result", message: `Implementasi: komponen + unit test untuk "${name}"` },
              { from: "developer", to: "qa", type: "review_request", message: `"${name}" selesai. Mohon direview.` },
              { from: "qa", to: "developer", type: "approval", message: `"${name}" siap deploy. рҹ‘Қ` },
            ],
            bugfix: [
              { from: "pm", to: "developer", type: "result", message: `Bug pada "${name}". Tolong diperbaiki.` },
              { from: "developer", to: "qa", type: "review_request", message: `Fix "${name}" siap diuji.` },
              { from: "qa", to: "developer", type: "approval", message: `Bug "${name}" terverifikasi. рҹ‘Қ` },
            ],
            review: [
              { from: "developer", to: "qa", type: "review_request", message: `Code review: "${name}"` },
              { from: "qa", to: "developer", type: "review_response", message: `Refactor fungsi X, tambah error handling.` },
              { from: "developer", to: "qa", type: "result", message: `Sudah diperbaiki.` },
              { from: "qa", to: "developer", type: "approval", message: `LGTM! вң…` },
            ],
          };

          const msgs = stages[tpl].map((s) => ({
            ...s,
            time: new Date().toISOString(),
            taskId,
            read: false,
          }));
          const all = readData();
          all.push(...msgs);
          saveData(all);
          log(`рҹҸ—пёҸ Pipeline ${tpl} "${name}" (${taskId})\n`);

          let out = `в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\nв•‘  рҹҸ—пёҸ  PIPELINE: ${tpl.toUpperCase()}${" ".repeat(30 - tpl.length)}в•‘\nв•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n`;
          out += `рҹ“Ӣ ${tpl === "feature" ? "PMвҶ’ArchitectвҶ’DeveloperвҶ’QA" : tpl === "bugfix" ? "PMвҶ’DeveloperвҶ’QA" : "DeveloperвҶ’QA"}\n`;
          out += `рҹҶ” ${taskId}\nрҹ”§ ${name}\n\n`;
          for (let i = 0; i < msgs.length; i++) {
            const m = msgs[i];
            out += `  ${i + 1}. ${LABELS[m.from] || m.from}\n     рҹ’¬ "${m.message}"\n     рҹ“Ё вҶ’ ${LABELS[m.to] || m.to}\n\n`;
          }
          out += `вң… Selesai! Lihat: inter_agent_conversation taskId=${taskId}\nрҹ“Ғ ${LOG}\n`;
          return out;
        },
      },
    },
  };
}) satisfies Plugin;
"}

