            out += `  ${a.emoji} ${a.name.padEnd(18)} рҹ“Ө ${String(sent).padStart(2)} рҹ“Ҙ ${String(recv).padStart(2)} ${unread > 0 ? `рҹҶ• ${unread}` : "вң…"}\n`;
          }
          out += `\n  ${"в”Җ".repeat(45)}\n  рҹҶ” Total: ${taskIds.size} task | рҹ’¬ ${messages.length} pesan\n\n`;
          for (const tid of taskIds) {
            const ms = messages.filter((m) => m.taskId === tid);
            const types = ms.map((m) => m.type as string);
            out += `  ${types.includes("approval") ? "вң…" : "рҹ”„"} ${tid.substring(0, 35).padEnd(35)} ${ms.length} msg\n`;
